INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (1,'accueil','fr','Où se situe Villa Plaisance ?','Villa Plaisance se trouve à Bédarrides, dans le Vaucluse (84370), au cœur du Triangle d\'Or provençal, à 8 minutes de Châteauneuf-du-Pape, 15 minutes d\'Avignon et 18 minutes d\'Orange.',1,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (2,'accueil','fr','Quelle est la différence entre chambres d\'hôtes et villa entière ?','De septembre à juin, nous accueillons en chambres d\'hôtes (2 chambres, petit-déjeuner inclus, piscine partagée). En juillet et août, la villa entière se loue en exclusivité (4 chambres, piscine privée, cuisine équipée, jusqu\'à 10 personnes).',2,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (3,'accueil','fr','Y a-t-il une piscine ?','Oui. La piscine mesure 12 mètres sur 6, elle est clôturée et sécurisée. En chambres d\'hôtes, elle est partagée avec les autres hôtes. En location villa, elle est entièrement privatisée.',3,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (4,'chambres-d-hotes','fr','Le petit-déjeuner est-il inclus ?','Oui, le petit-déjeuner maison est inclus dans le tarif B&B. Il est servi de 7h30 à 10h en terrasse (temps le permettant) ou en véranda, avec confitures artisanales, viennoiseries, pain frais, fromages provençaux, fruits de saison, jus d\'orange pressé, café, thé et tisanes bio.',1,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (5,'chambres-d-hotes','fr','Les chambres sont-elles climatisées ?','Oui, les deux chambres (Verte et Bleue) sont équipées de climatisation réversible et du wifi gratuit.',2,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (6,'chambres-d-hotes','fr','Peut-on accueillir des enfants en chambres d\'hôtes ?','Oui, la Chambre Bleue dispose d\'un clic-clac pouvant accueillir une personne supplémentaire, ce qui en fait une chambre idéale pour les familles.',3,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (7,'chambres-d-hotes','fr','À quelle période les chambres d\'hôtes sont-elles disponibles ?','Les chambres d\'hôtes sont ouvertes de septembre à juin. En juillet et août, la villa se loue en exclusivité.',4,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (8,'chambres-d-hotes','fr','Comment se rendre à Villa Plaisance ?','Villa Plaisance est à 15 min d\'Avignon par la RN7 ou l\'autoroute A7 (sortie Avignon-Nord). En train : gare Avignon-Centre ou Avignon TGV avec taxi (15 min). Les coordonnées GPS sont transmises lors de la confirmation de réservation.',5,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (9,'chambres-d-hotes','fr','Y a-t-il un parking ?','Oui, un parking privé gratuit est disponible sur place pour tous les hôtes.',6,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (10,'location-villa-provence','fr','Combien de personnes la villa peut-elle accueillir ?','La villa entière accueille jusqu\'à 10 personnes réparties dans 4 chambres : une suite parentale avec lit king et salle de bain privée, la Chambre Bleue (queen 160×200), la Chambre de l\'Arche (double 160×200) et la Chambre Années 70 (2 lits simples jumelables). Lit bébé et chaise haute disponibles sur demande.',1,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (11,'location-villa-provence','fr','La piscine est-elle privée en location villa ?','Oui, en location villa entière la piscine de 12×6 m est exclusivement réservée à votre groupe, 24h/24. Aucune autre famille n\'y a accès. Elle peut être chauffée en option dès le mois de juillet.',2,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (12,'location-villa-provence','fr','La cuisine est-elle équipée ?','Oui, la cuisine est entièrement équipée : four, plaques, lave-vaisselle, micro-ondes, réfrigérateur, ustensiles de cuisine et vaisselle pour 10 personnes.',3,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (13,'location-villa-provence','fr','Le linge de maison est-il fourni ?','Oui, les draps, serviettes de bain et serviettes de piscine sont fournis et changés chaque semaine.',4,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (14,'location-villa-provence','fr','Quelle est la durée minimum de location ?','En haute saison (juillet-août), la durée minimum est d\'une semaine, du samedi au samedi.',5,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (15,'location-villa-provence','fr','Y a-t-il des commerces à proximité ?','Oui, Bédarrides dispose de boulangeries, supérette, restaurants et pharmacie. Le supermarché le plus proche est à Sorgues, à 5 minutes en voiture.',6,1,'2026-03-29 14:51:46');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (16,'chambres-d-hotes','fr','La piscine est-elle disponible toute la saison B&B ?','La piscine partagée (12×6 m) est disponible de mai à octobre selon conditions météo. Elle est accessible à tous les hôtes présents. Transats et parasols sont à disposition.',7,1,'2026-03-29 18:00:15');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (17,'chambres-d-hotes','fr','Comment réserver les chambres d\'hôtes ?','Vous pouvez réserver via Airbnb ou Booking.com pour un paiement sécurisé, ou nous contacter directement pour un tarif préférentiel. Réservation directe = meilleur tarif garanti.',8,1,'2026-03-29 18:00:15');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (18,'location-villa-provence','fr','Y a-t-il un service de ménage ou de chef à domicile ?','Le ménage de fin de séjour est inclus dans le tarif. Un ménage intermédiaire peut être ajouté en option. Nous pouvons également vous mettre en contact avec des chefs cuisiniers locaux pour des dîners à domicile sur réservation.',7,1,'2026-03-29 18:01:52');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (19,'location-villa-provence','fr','Comment réserver la villa entière ?','Vous pouvez réserver via Abritel ou Booking.com pour un paiement sécurisé en ligne, ou nous contacter directement pour un devis personnalisé, des options (chauffage piscine, chef, ménage) ou des tarifs long séjour. Réservation directe = meilleur tarif garanti.',8,1,'2026-03-29 18:01:52');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (20,'accueil','en','Where is Villa Plaisance located?','Villa Plaisance is in Bédarrides, Vaucluse (84370), in the heart of Provence\'s Golden Triangle — 8 minutes from Châteauneuf-du-Pape, 15 min from Avignon, 18 min from Orange. Easy access via the A7 motorway (Avignon-Nord exit).',1,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (21,'accueil','es','¿Dónde se encuentra Villa Plaisance?','Villa Plaisance está en Bédarrides, Vaucluse (84370), en el corazón del Triángulo de Oro provenzal — a 8 minutos de Châteauneuf-du-Pape, 15 min de Aviñón, 18 min de Orange.',1,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (22,'accueil','en','What is the difference between B&B and villa rental?','From September to June, we welcome guests in B&B rooms (2 rooms, breakfast included, shared pool). In July and August, the entire villa is rented exclusively: 4 bedrooms, private pool, full kitchen.',2,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (23,'accueil','es','¿Cuál es la diferencia entre B&B y villa entera?','De septiembre a junio, recibimos huéspedes en habitaciones B&B (2 habitaciones, desayuno incluido, piscina compartida). En julio y agosto, la villa entera se alquila en exclusiva: 4 habitaciones, piscina privada, cocina equipada.',2,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (24,'accueil','en','Is there a swimming pool?','Yes. The pool measures 12 by 6 metres, fenced and secure. In B&B mode, it is shared with other guests. In villa rental, it is exclusively yours.',3,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (25,'accueil','es','¿Hay piscina?','Sí. La piscina mide 12 por 6 metros, está vallada y es segura. En modo B&B se comparte con otros huéspedes. En alquiler de villa, es exclusivamente suya.',3,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (26,'chambres-d-hotes','en','Is breakfast included?','Yes, homemade breakfast is included in the B&B rate. Served from 7:30 to 10:00 on the terrace or in the veranda, with artisanal jams, fresh bread, pastries, seasonal fruit, cheeses, garden eggs, juice, coffee and tea.',1,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (27,'chambres-d-hotes','es','¿El desayuno está incluido?','Sí, el desayuno casero está incluido en la tarifa B&B. Se sirve de 7:30 a 10:00 en la terraza o en la galería, con mermeladas artesanales, pan fresco, bollería, fruta de temporada, quesos, huevos del jardín, zumo, café y té.',1,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (28,'chambres-d-hotes','en','Are the rooms air-conditioned?','Yes, both rooms (Green and Blue) have reversible air conditioning and free Wi-Fi.',2,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (29,'chambres-d-hotes','es','¿Las habitaciones tienen aire acondicionado?','Sí, ambas habitaciones (Verde y Azul) disponen de aire acondicionado reversible y Wi-Fi gratuito.',2,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (30,'chambres-d-hotes','en','Can you accommodate children in B&B?','Yes, the Blue Room has a sofa bed for an extra person, making it ideal for families.',3,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (31,'chambres-d-hotes','es','¿Se admiten niños en B&B?','Sí, la Habitación Azul dispone de un sofá cama para una persona adicional, ideal para familias.',3,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (32,'chambres-d-hotes','en','When are the B&B rooms available?','The B&B rooms are open from September to June. In July and August, the villa is rented exclusively.',4,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (33,'chambres-d-hotes','es','¿En qué periodo están disponibles las habitaciones?','Las habitaciones B&B están abiertas de septiembre a junio. En julio y agosto, la villa se alquila en exclusiva.',4,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (34,'chambres-d-hotes','en','How do I get to Villa Plaisance?','Villa Plaisance is 15 min from Avignon via the RN7 or A7 motorway (Avignon-Nord exit). By train: Avignon-Centre or Avignon TGV station, then taxi (15 min).',5,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (35,'chambres-d-hotes','es','¿Cómo llegar a Villa Plaisance?','Villa Plaisance está a 15 min de Aviñón por la RN7 o la autopista A7 (salida Avignon-Nord). En tren: estación Avignon-Centre o Avignon TGV, luego taxi (15 min).',5,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (36,'chambres-d-hotes','en','Is there parking?','Yes, free private parking is available on site for all guests.',6,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (37,'chambres-d-hotes','es','¿Hay aparcamiento?','Sí, hay un aparcamiento privado gratuito en el recinto para todos los huéspedes.',6,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (38,'chambres-d-hotes','en','Is the pool available throughout the B&B season?','The shared pool (12×6 m) is available from May to October depending on weather. Sun loungers and parasols are provided.',7,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (39,'chambres-d-hotes','es','¿La piscina está disponible toda la temporada B&B?','La piscina compartida (12×6 m) está disponible de mayo a octubre según las condiciones meteorológicas. Se proporcionan tumbonas y sombrillas.',7,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (40,'chambres-d-hotes','en','How do I book the B&B?','You can book via Airbnb or Booking.com for secure payment, or contact us directly for a preferential rate. Direct booking = best rate guaranteed.',8,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (41,'chambres-d-hotes','es','¿Cómo reservar el B&B?','Puede reservar a través de Airbnb o Booking.com para un pago seguro, o contactarnos directamente para una tarifa preferente. Reserva directa = mejor tarifa garantizada.',8,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (42,'location-villa-provence','en','How many guests can the villa accommodate?','The entire villa accommodates up to 10 people in 4 bedrooms: a master suite with king bed and private bathroom, the Blue Room, the Arch Room and the 70s Room.',1,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (43,'location-villa-provence','es','¿Cuántas personas puede alojar la villa?','La villa entera acoge hasta 10 personas en 4 habitaciones: una suite principal con cama king y baño privado, la Habitación Azul, la Habitación Arco y la Habitación 70.',1,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (44,'location-villa-provence','en','Is the pool private in villa rental?','Yes, in villa rental the 12×6 m pool is exclusively reserved for your group, 24/7. No other family has access. It can be heated on request.',2,1,'2026-03-30 10:04:32');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (45,'location-villa-provence','es','¿La piscina es privada en alquiler de villa?','Sí, en alquiler de villa la piscina de 12×6 m está reservada exclusivamente para su grupo, 24/7. Se puede calentar bajo petición.',2,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (46,'location-villa-provence','en','Is the kitchen fully equipped?','Yes, the kitchen is fully equipped: oven, hob, dishwasher, microwave, fridge, utensils and tableware for 10 people.',3,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (47,'location-villa-provence','es','¿La cocina está equipada?','Sí, la cocina está totalmente equipada: horno, placa, lavavajillas, microondas, frigorífico, utensilios y vajilla para 10 personas.',3,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (48,'location-villa-provence','en','Is linen provided?','Yes, bed sheets, bath towels and pool towels are provided and changed weekly.',4,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (49,'location-villa-provence','es','¿Se proporciona ropa de cama?','Sí, se proporcionan sábanas, toallas de baño y toallas de piscina, con cambio semanal.',4,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (50,'location-villa-provence','en','What is the minimum rental period?','In high season (July–August), the minimum stay is one week, Saturday to Saturday.',5,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (51,'location-villa-provence','es','¿Cuál es la duración mínima del alquiler?','En temporada alta (julio–agosto), la estancia mínima es de una semana, de sábado a sábado.',5,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (52,'location-villa-provence','en','Are there shops nearby?','Yes, Bédarrides has bakeries, a small supermarket, restaurants and a pharmacy. The nearest supermarket is in Sorgues, 5 minutes by car.',6,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (53,'location-villa-provence','es','¿Hay tiendas cerca?','Sí, Bédarrides tiene panaderías, supermercado, restaurantes y farmacia. El supermercado más cercano está en Sorgues, a 5 minutos en coche.',6,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (54,'location-villa-provence','en','Is there a cleaning or private chef service?','End-of-stay cleaning is included. Mid-stay cleaning can be added. We can also arrange a private chef or catering service.',7,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (55,'location-villa-provence','es','¿Hay servicio de limpieza o chef privado?','La limpieza de fin de estancia está incluida. Se puede añadir limpieza intermedia. También podemos organizar un chef privado o servicio de catering.',7,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (56,'location-villa-provence','en','How do I book the villa?','You can book via Abritel or Booking.com for secure online payment, or contact us directly for a personalised quote, specific dates or a multi-week discount.',8,1,'2026-03-30 10:04:33');
INSERT INTO `vp_faq` (`id`, `page_slug`, `lang`, `question`, `answer`, `position`, `active`, `created_at`) VALUES (57,'location-villa-provence','es','¿Cómo reservar la villa entera?','Puede reservar a través de Abritel o Booking.com para un pago seguro en línea, o contactarnos directamente para un presupuesto personalizado.',8,1,'2026-03-30 10:04:33');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (34,'bb','Bienvenue','Bienvenue à Villa Plaisance ! Nous sommes ravis de vous accueillir dans notre maison provençale à Bédarrides, au cœur du triangle d\'or Avignon–Orange–Châteauneuf-du-Pape.\n\nN\'hésitez pas à nous solliciter pour quoi que ce soit : recommandations, itinéraires, réservations de restaurants. Nous sommes là pour rendre votre séjour agréable.\n\nBon séjour en Provence !',1,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (35,'bb','Welcome','Welcome to Villa Plaisance! We are delighted to have you in our Provençal home in Bédarrides, in the heart of the golden triangle: Avignon–Orange–Châteauneuf-du-Pape.\n\nPlease don\'t hesitate to ask us for anything: recommendations, itineraries, restaurant reservations. We\'re here to make your stay wonderful.\n\nEnjoy your time in Provence!',1,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (36,'bb','Bienvenida','¡Bienvenidos a Villa Plaisance! Estamos encantados de recibirles en nuestra casa provenzal en Bédarrides, en el corazón del triángulo de oro Aviñón–Orange–Châteauneuf-du-Pape.\n\nNo duden en pedirnos lo que necesiten: recomendaciones, itinerarios, reservas de restaurantes. Estamos aquí para que su estancia sea agradable.\n\n¡Feliz estancia en Provenza!',1,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (37,'bb','Votre chambre','Chaque chambre dispose de la climatisation réversible (chaud/froid), du Wifi, d\'une salle de bain privative et de linge de toilette.\n\nChambre Verte — Lit 160×200, vue jardin, rez-de-chaussée, TV.\nChambre Bleue — 2 lits 90×200 jumelables + clic-clac, bibliothèque 300 livres.\n\nMerci de ne pas déplacer les meubles et de laisser la chambre dans un état correct à votre départ.',2,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (38,'bb','Your room','Each room has reversible air conditioning (heating/cooling), WiFi, a private bathroom and towels.\n\nGreen Room — Queen bed (160×200), garden view, ground floor, TV.\nBlue Room — 2 single beds (90×200, joinable) + sofa bed, 300-book library.\n\nPlease do not move furniture and leave the room tidy when you check out.',2,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (39,'bb','Su habitación','Cada habitación dispone de aire acondicionado reversible (frío/calor), Wifi, baño privado y toallas.\n\nHabitación Verde — Cama 160×200, vista al jardín, planta baja, TV.\nHabitación Azul — 2 camas 90×200 unibles + sofá cama, biblioteca de 300 libros.\n\nPor favor, no muevan los muebles y dejen la habitación ordenada al salir.',2,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (40,'bb','Petit-déjeuner','Servi chaque matin de 8h30 à 10h00, en terrasse (selon la météo) ou sous la véranda.\n\nAu menu : confitures artisanales (figue, abricot, lavande), pain frais, viennoiseries, fruits de saison, fromages locaux, œufs, jus de fruits, café, thé.\n\nTout est préparé maison avec des produits locaux et de saison. Le menu change chaque jour.\n\nMerci de nous prévenir la veille si vous avez des allergies ou restrictions alimentaires.',3,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (41,'bb','Breakfast','Served every morning from 8:30am to 10:00am, on the terrace (weather permitting) or in the veranda.\n\nOn the menu: artisanal jams (fig, apricot, lavender), fresh bread, pastries, seasonal fruit, local cheeses, eggs, fruit juice, coffee, tea.\n\nEverything is homemade with local, seasonal produce. The menu changes daily.\n\nPlease let us know the evening before if you have any allergies or dietary requirements.',3,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (42,'bb','Desayuno','Se sirve cada mañana de 8:30 a 10:00, en la terraza (según el tiempo) o en la galería.\n\nEn el menú: mermeladas artesanales (higo, albaricoque, lavanda), pan fresco, bollería, fruta de temporada, quesos locales, huevos, zumo de frutas, café, té.\n\nTodo es casero con productos locales y de temporada. El menú cambia cada día.\n\nPor favor, avísennos la noche anterior si tienen alergias o restricciones alimentarias.',3,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (43,'bb','Wifi','Réseau : VillaPlaisance\nMot de passe : (affiché dans votre chambre)\n\nLe Wifi couvre toute la maison et le jardin. En cas de souci de connexion, n\'hésitez pas à nous en parler.',4,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (44,'bb','WiFi','Network: VillaPlaisance\nPassword: (displayed in your room)\n\nWiFi covers the entire house and garden. If you experience any connection issues, please let us know.',4,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (45,'bb','Wifi','Red: VillaPlaisance\nContraseña: (indicada en su habitación)\n\nEl Wifi cubre toda la casa y el jardín. Si tienen algún problema de conexión, no duden en avisarnos.',4,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (46,'bb','Piscine','La piscine (12m × 6m) est partagée avec les autres hôtes.\n\nHoraires : 9h – 20h\nDouche obligatoire avant la baignade\nServiettes de piscine fournies (sur les transats)\nParasols et chaises longues à disposition\n\nSaison piscine : mai à octobre.\n\nPour votre sécurité, la piscine est clôturée. Merci de bien refermer le portillon après votre passage.',5,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (47,'bb','Swimming pool','The pool (12m × 6m) is shared with other guests.\n\nHours: 9am – 8pm\nShower required before swimming\nPool towels provided (on the sun loungers)\nParasols and lounge chairs available\n\nPool season: May to October.\n\nFor safety, the pool is fenced. Please close the gate behind you.',5,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (48,'bb','Piscina','La piscina (12m × 6m) es compartida con los demás huéspedes.\n\nHorario: 9:00 – 20:00\nDucha obligatoria antes del baño\nToallas de piscina proporcionadas (en las tumbonas)\nSombrillas y tumbonas a disposición\n\nTemporada de piscina: mayo a octubre.\n\nPor seguridad, la piscina está vallada. Por favor, cierren la puerta al pasar.',5,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (49,'bb','Espaces extérieurs','Le jardin de 1 500 m² est à votre disposition : oliviers centenaires, lavande, romarin, herbes aromatiques, potager d\'été.\n\nVous trouverez aussi :\n— Une terrasse couverte de 40 m² orientée sud\n— Un barbecue (charbon fourni, merci de nettoyer après usage)\n— Un terrain de pétanque (boules dans le coffre à côté)\n— Une balançoire pour les enfants\n\nMerci de respecter le calme du jardin, surtout après 22h.',6,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (50,'bb','Outdoor spaces','The 1,500 m² garden is at your disposal: century-old olive trees, lavender, rosemary, aromatic herbs, summer vegetable garden.\n\nYou will also find:\n— A 40 m² covered south-facing terrace\n— A barbecue (charcoal provided, please clean after use)\n— A pétanque court (boules in the chest nearby)\n— A swing for children\n\nPlease respect the quiet of the garden, especially after 10pm.',6,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (51,'bb','Espacios exteriores','El jardín de 1.500 m² está a su disposición: olivos centenarios, lavanda, romero, hierbas aromáticas, huerto de verano.\n\nTambién encontrarán:\n— Una terraza cubierta de 40 m² orientada al sur\n— Una barbacoa (carbón proporcionado, limpiar después de usar)\n— Una cancha de petanca (bolas en el cofre al lado)\n— Un columpio para los niños\n\nPor favor, respeten la tranquilidad del jardín, especialmente después de las 22:00.',6,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (52,'bb','Parking','Un parking privé gratuit est disponible dans la propriété. Vous pouvez vous garer librement à votre arrivée.\n\nSi vous arrivez en train, la gare de Bédarrides est à 10 minutes à pied. Nous pouvons venir vous chercher sur demande.',7,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (53,'bb','Parking','Free private parking is available on the property. You can park freely upon arrival.\n\nIf you arrive by train, Bédarrides station is a 10-minute walk. We can pick you up on request.',7,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (54,'bb','Aparcamiento','Hay aparcamiento privado gratuito en la propiedad. Pueden aparcar libremente a su llegada.\n\nSi llegan en tren, la estación de Bédarrides está a 10 minutos a pie. Podemos recogerles si lo solicitan.',7,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (55,'bb','Aux alentours','Villa Plaisance est idéalement située dans le « triangle d\'or » de la Provence :\n\n— Châteauneuf-du-Pape : 8 min (dégustations de vin)\n— Avignon : 15 min (Palais des Papes, Pont d\'Avignon)\n— Orange : 18 min (Théâtre antique romain)\n— L\'Isle-sur-la-Sorgue : 25 min (antiquaires, marché le dimanche)\n— Pont du Gard : 30 min (aqueduc romain, UNESCO)\n— Fontaine de Vaucluse : 30 min\n— Vaison-la-Romaine : 35 min\n— Gordes : 42 min (village perché)\n— Les Baux-de-Provence : 45 min (Carrières de Lumières)\n— Mont Ventoux : 45 min\n\nN\'hésitez pas à nous demander nos bonnes adresses !',8,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (56,'bb','Nearby','Villa Plaisance is ideally located in Provence\'s \"golden triangle\":\n\n— Châteauneuf-du-Pape: 8 min (wine tasting)\n— Avignon: 15 min (Papal Palace, Pont d\'Avignon)\n— Orange: 18 min (Roman Theatre)\n— L\'Isle-sur-la-Sorgue: 25 min (antiques, Sunday market)\n— Pont du Gard: 30 min (Roman aqueduct, UNESCO)\n— Fontaine de Vaucluse: 30 min\n— Vaison-la-Romaine: 35 min\n— Gordes: 42 min (hilltop village)\n— Les Baux-de-Provence: 45 min (Carrières de Lumières)\n— Mont Ventoux: 45 min\n\nAsk us for our favourite local tips!',8,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (57,'bb','Alrededores','Villa Plaisance está idealmente situada en el \"triángulo de oro\" de la Provenza:\n\n— Châteauneuf-du-Pape: 8 min (catas de vino)\n— Aviñón: 15 min (Palacio de los Papas, Puente de Aviñón)\n— Orange: 18 min (Teatro Romano)\n— L\'Isle-sur-la-Sorgue: 25 min (anticuarios, mercado dominical)\n— Pont du Gard: 30 min (acueducto romano, UNESCO)\n— Fontaine de Vaucluse: 30 min\n— Vaison-la-Romaine: 35 min\n— Gordes: 42 min (pueblo en la colina)\n— Les Baux-de-Provence: 45 min (Carrières de Lumières)\n— Mont Ventoux: 45 min\n\n¡Pídannos nuestras mejores direcciones!',8,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (58,'bb','Marchés provençaux','Les marchés sont l\'âme de la Provence. Voici ceux à ne pas manquer :\n\n— Lundi : Bédarrides (petit marché local, place du village)\n— Mardi : Vaison-la-Romaine\n— Mercredi : Sorgues\n— Jeudi : Orange, Villeneuve-lès-Avignon\n— Vendredi : Carpentras (le plus grand, avec les truffes en saison)\n— Samedi : Avignon (Les Halles, marché couvert toute l\'année)\n— Dimanche : L\'Isle-sur-la-Sorgue (brocante + alimentaire, incontournable)\n\nArrivez avant 10h pour profiter pleinement de l\'ambiance.',9,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (59,'bb','Provençal markets','Markets are the soul of Provence. Here are the ones not to miss:\n\n— Monday: Bédarrides (small local market, village square)\n— Tuesday: Vaison-la-Romaine\n— Wednesday: Sorgues\n— Thursday: Orange, Villeneuve-lès-Avignon\n— Friday: Carpentras (the largest, with truffles in season)\n— Saturday: Avignon (Les Halles, covered market year-round)\n— Sunday: L\'Isle-sur-la-Sorgue (antiques + food market, a must!)\n\nArrive before 10am to enjoy the atmosphere at its best.',9,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (60,'bb','Mercados provenzales','Los mercados son el alma de la Provenza. Estos son los imprescindibles:\n\n— Lunes: Bédarrides (pequeño mercado local, plaza del pueblo)\n— Martes: Vaison-la-Romaine\n— Miércoles: Sorgues\n— Jueves: Orange, Villeneuve-lès-Avignon\n— Viernes: Carpentras (el más grande, con trufas en temporada)\n— Sábado: Aviñón (Les Halles, mercado cubierto todo el año)\n— Domingo: L\'Isle-sur-la-Sorgue (antigüedades + alimentación, ¡imprescindible!)\n\nLleguen antes de las 10:00 para disfrutar plenamente del ambiente.',9,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (61,'bb','Restaurants que nous aimons','Voici quelques adresses testées et approuvées :\n\n— Le Numéro 3 (Bédarrides) — Bistrot au bord de l\'Ouvèze, cuisine locale\n— Impérial Bus Diner (Sorgues) — Burgers généreux, ambiance décontractée\n— La Mère Germaine (Châteauneuf-du-Pape) — Gastronomique, vue vignes\n— Le Bercail (Avignon) — Terrasse sur l\'île de la Barthelasse\n— Christian Étienne (Avignon) — Étoilé Michelin, face au Palais\n\nPensez à réserver, surtout en saison. Nous pouvons vous aider.',10,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (62,'bb','Restaurants we love','Here are some tried and tested addresses:\n\n— Le Numéro 3 (Bédarrides) — Bistro on the Ouvèze river, local cuisine\n— Impérial Bus Diner (Sorgues) — Generous burgers, relaxed atmosphere\n— La Mère Germaine (Châteauneuf-du-Pape) — Fine dining, vineyard views\n— Le Bercail (Avignon) — Terrace on Barthelasse island\n— Christian Étienne (Avignon) — Michelin-starred, facing the Palace\n\nRemember to book, especially in high season. We can help with reservations.',10,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (63,'bb','Restaurantes que nos gustan','Estas son algunas direcciones probadas y aprobadas:\n\n— Le Numéro 3 (Bédarrides) — Bistró a orillas del Ouvèze, cocina local\n— Impérial Bus Diner (Sorgues) — Hamburguesas generosas, ambiente relajado\n— La Mère Germaine (Châteauneuf-du-Pape) — Gastronómico, vistas a viñedos\n— Le Bercail (Aviñón) — Terraza en la isla de la Barthelasse\n— Christian Étienne (Aviñón) — Estrella Michelin, frente al Palacio\n\nRecuerden reservar, sobre todo en temporada alta. Podemos ayudarles.',10,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (64,'bb','Numéros utiles','Urgences : 112 (européen) / 15 (SAMU) / 18 (pompiers)\nPolice : 17\nPharmacies de garde : 3237\n\nHôpital le plus proche : Centre Hospitalier d\'Avignon — 20 min\nAdresse : 305 Rue Raoul Follereau, 84000 Avignon\n\nPharmacie Bédarrides : Place de la Mairie (horaires affichés en vitrine)\nMédecin Bédarrides : Cabinet médical, rue de la République\n\nVos hôtes : contactez-nous à tout moment en cas de besoin.',11,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (65,'bb','Useful numbers','Emergencies: 112 (European) / 15 (ambulance) / 18 (fire)\nPolice: 17\nOn-call pharmacies: 3237\n\nNearest hospital: Centre Hospitalier d\'Avignon — 20 min\nAddress: 305 Rue Raoul Follereau, 84000 Avignon\n\nBédarrides pharmacy: Place de la Mairie (hours posted on window)\nBédarrides doctor: Medical practice, rue de la République\n\nYour hosts: contact us at any time if you need anything.',11,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (66,'bb','Números útiles','Urgencias: 112 (europeo) / 15 (ambulancia) / 18 (bomberos)\nPolicía: 17\nFarmacias de guardia: 3237\n\nHospital más cercano: Centre Hospitalier d\'Avignon — 20 min\nDirección: 305 Rue Raoul Follereau, 84000 Avignon\n\nFarmacia Bédarrides: Place de la Mairie (horarios en el escaparate)\nMédico Bédarrides: Consultorio médico, rue de la République\n\nSus anfitriones: contáctennos en cualquier momento si necesitan algo.',11,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (67,'bb','Départ','Le jour du départ, merci de :\n— Laisser les clés dans la chambre\n— Fermer les volets et fenêtres\n— Éteindre la climatisation\n\nPas besoin de faire le ménage, mais nous apprécions une chambre laissée en ordre.\n\nN\'oubliez pas de nous laisser un avis sur Airbnb ou Booking — cela nous aide énormément !\n\nMerci pour votre visite et à bientôt en Provence.',12,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (68,'bb','Checkout','On departure day, please:\n— Leave the keys in the room\n— Close the shutters and windows\n— Turn off the air conditioning\n\nNo need to clean, but we appreciate a tidy room.\n\nDon\'t forget to leave us a review on Airbnb or Booking — it helps us enormously!\n\nThank you for your visit and see you again in Provence.',12,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (69,'bb','Salida','El día de la salida, por favor:\n— Dejen las llaves en la habitación\n— Cierren las persianas y ventanas\n— Apaguen el aire acondicionado\n\nNo es necesario limpiar, pero agradecemos una habitación ordenada.\n\n¡No olviden dejarnos una reseña en Airbnb o Booking — nos ayuda mucho!\n\nGracias por su visita y hasta pronto en Provenza.',12,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (70,'villa','Bienvenue','Bienvenue à Villa Plaisance ! Toute la maison est à vous pour la durée de votre séjour.\n\nVous disposez de 4 chambres, d\'une piscine privée de 12m × 6m, d\'un jardin de 1 500 m², d\'une cuisine entièrement équipée et de plusieurs terrasses.\n\nLa villa accueille jusqu\'à 10 personnes. Le séjour est autonome : vous avez les clés, l\'espace et la liberté.\n\nCe livret contient tout ce qu\'il faut savoir. Bonne découverte de la Provence !',1,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (71,'villa','Welcome','Welcome to Villa Plaisance! The entire house is yours for the duration of your stay.\n\nYou have 4 bedrooms, a private 12m × 6m pool, a 1,500 m² garden, a fully equipped kitchen and several terraces.\n\nThe villa accommodates up to 10 guests. Your stay is self-catering: you have the keys, the space and the freedom.\n\nThis booklet contains everything you need to know. Enjoy discovering Provence!',1,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (72,'villa','Bienvenida','¡Bienvenidos a Villa Plaisance! Toda la casa es suya durante su estancia.\n\nDisponen de 4 habitaciones, una piscina privada de 12m × 6m, un jardín de 1.500 m², una cocina totalmente equipada y varias terrazas.\n\nLa villa acoge hasta 10 personas. La estancia es autónoma: tienen las llaves, el espacio y la libertad.\n\nEsta guía contiene todo lo que necesitan saber. ¡Disfruten de la Provenza!',1,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (73,'villa','Les chambres','La villa dispose de 4 chambres, toutes climatisées :\n\n1. Chambre Verte — Lit 160×200, vue jardin, rez-de-chaussée, TV\n2. Chambre Bleue — 2 lits 90×200 jumelables + clic-clac, bibliothèque 300 livres\n3. Chambre Arche — Lit 140×180, arche bleue nuit peinte, bibliothèques sol-plafond, accès jardin\n4. Chambre 70 — Lit double, mobilier vintage années 70, porte-fenêtre sur jardin\n\nDraps et serviettes fournis, changés une fois par semaine.\n\nMerci de ne pas déplacer les meubles entre les chambres.',2,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (74,'villa','Bedrooms','The villa has 4 bedrooms, all air-conditioned:\n\n1. Green Room — Queen bed (160×200), garden view, ground floor, TV\n2. Blue Room — 2 single beds (90×200, joinable) + sofa bed, 300-book library\n3. Arch Room — Double bed (140×180), blue night arch, floor-to-ceiling bookshelves, garden access\n4. Room 70 — Double bed, vintage 1970s furniture, French doors to garden\n\nSheets and towels provided, changed once a week.\n\nPlease do not move furniture between rooms.',2,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (75,'villa','Habitaciones','La villa dispone de 4 habitaciones, todas con aire acondicionado:\n\n1. Habitación Verde — Cama 160×200, vista al jardín, planta baja, TV\n2. Habitación Azul — 2 camas 90×200 unibles + sofá cama, biblioteca de 300 libros\n3. Habitación Arco — Cama 140×180, arco azul noche, estanterías de suelo a techo, acceso al jardín\n4. Habitación 70 — Cama doble, mobiliario vintage años 70, puerta ventana al jardín\n\nSábanas y toallas proporcionadas, se cambian una vez por semana.\n\nPor favor, no muevan los muebles entre habitaciones.',2,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (76,'villa','Cuisine','La cuisine est entièrement équipée pour 10 personnes :\n\nFour, plaques de cuisson, micro-ondes, lave-vaisselle, réfrigérateur-congélateur, cafetière, bouilloire, grille-pain.\n\nVaisselle, couverts, verres, casseroles, poêles, plats : tout est en place.\n\nÉpices de base, huile d\'olive, sel, poivre, vinaigre sont à votre disposition.\n\nMerci de :\n— Lancer le lave-vaisselle chaque soir\n— Laisser la cuisine propre à votre départ\n— Jeter les denrées périssables non utilisées\n\nLe supermarché le plus proche est à Sorgues (5 min en voiture).',3,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (77,'villa','Kitchen','The kitchen is fully equipped for 10 people:\n\nOven, hob, microwave, dishwasher, fridge-freezer, coffee maker, kettle, toaster.\n\nPlates, cutlery, glasses, pots, pans, baking dishes: everything is in place.\n\nBasic spices, olive oil, salt, pepper, vinegar are provided.\n\nPlease:\n— Run the dishwasher every evening\n— Leave the kitchen clean on departure\n— Discard unused perishable food\n\nThe nearest supermarket is in Sorgues (5 min by car).',3,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (78,'villa','Cocina','La cocina está totalmente equipada para 10 personas:\n\nHorno, placa de cocción, microondas, lavavajillas, frigorífico-congelador, cafetera, hervidor, tostadora.\n\nPlatos, cubiertos, vasos, ollas, sartenes, fuentes: todo está en su sitio.\n\nEspecias básicas, aceite de oliva, sal, pimienta, vinagre están a su disposición.\n\nPor favor:\n— Pongan el lavavajillas cada noche\n— Dejen la cocina limpia al salir\n— Tiren los alimentos perecederos no utilizados\n\nEl supermercado más cercano está en Sorgues (5 min en coche).',3,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (79,'villa','Wifi','Réseau : VillaPlaisance\nMot de passe : (affiché dans le salon)\n\nLe Wifi couvre toute la maison et le jardin. En cas de souci de connexion, redémarrez la box (salon, meuble TV) en la débranchant 30 secondes.',4,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (80,'villa','WiFi','Network: VillaPlaisance\nPassword: (displayed in the living room)\n\nWiFi covers the entire house and garden. If you experience connection issues, restart the router (living room, TV unit) by unplugging it for 30 seconds.',4,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (81,'villa','Wifi','Red: VillaPlaisance\nContraseña: (indicada en el salón)\n\nEl Wifi cubre toda la casa y el jardín. Si tienen problemas de conexión, reinicien el router (salón, mueble de TV) desenchufándolo 30 segundos.',4,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (82,'villa','Piscine','La piscine (12m × 6m) est privée et réservée exclusivement à votre groupe.\n\nHoraires recommandés : 9h – 21h\nServiettes de piscine fournies (dans le coffre à côté de la piscine)\nDouche extérieure disponible\nTransats, parasols et mobilier de jardin autour du bassin\n\nIMPORTANT :\n— La piscine est clôturée. Merci de toujours refermer le portillon.\n— Les enfants doivent être surveillés en permanence par un adulte.\n— Pas de plongeons (profondeur maximale : 1m80).\n— Pas de verre au bord de la piscine (utilisez les gobelets en plastique fournis).',5,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (83,'villa','Swimming pool','The pool (12m × 6m) is private, reserved exclusively for your group.\n\nRecommended hours: 9am – 9pm\nPool towels provided (in the chest next to the pool)\nOutdoor shower available\nSun loungers, parasols and garden furniture around the pool\n\nIMPORTANT:\n— The pool is fenced. Please always close the gate.\n— Children must be supervised by an adult at all times.\n— No diving (maximum depth: 1.80m).\n— No glass by the pool (use the plastic cups provided).',5,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (84,'villa','Piscina','La piscina (12m × 6m) es privada, reservada exclusivamente para su grupo.\n\nHorario recomendado: 9:00 – 21:00\nToallas de piscina proporcionadas (en el cofre junto a la piscina)\nDucha exterior disponible\nTumbonas, sombrillas y mobiliario de jardín alrededor\n\nIMPORTANTE:\n— La piscina está vallada. Por favor, cierren siempre la puerta.\n— Los niños deben estar vigilados por un adulto en todo momento.\n— No tirarse de cabeza (profundidad máxima: 1,80m).\n— No llevar vasos de cristal a la piscina (usen los vasos de plástico proporcionados).',5,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (85,'villa','Espaces extérieurs','Le jardin de 1 500 m² est entièrement à vous :\n\n— Terrasse couverte de 40 m² (orientée sud, idéale pour les repas)\n— Barbecue charbon (charbon fourni dans le coffre, merci de nettoyer la grille après usage)\n— Terrain de pétanque (boules dans le coffre en bois)\n— Balançoire pour les enfants\n— Oliviers centenaires, lavande, romarin, potager\n— Vue sur les vignes de Châteauneuf-du-Pape\n\nMerci de ramasser les jouets et objets chaque soir pour éviter que le vent ne les emporte.',6,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (86,'villa','Outdoor spaces','The 1,500 m² garden is entirely yours:\n\n— 40 m² covered terrace (south-facing, ideal for meals)\n— Charcoal barbecue (charcoal provided in the chest, please clean the grill after use)\n— Pétanque court (boules in the wooden chest)\n— Swing for children\n— Century-old olive trees, lavender, rosemary, vegetable garden\n— Views over Châteauneuf-du-Pape vineyards\n\nPlease collect toys and belongings each evening to prevent the wind carrying them away.',6,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (87,'villa','Espacios exteriores','El jardín de 1.500 m² es enteramente suyo:\n\n— Terraza cubierta de 40 m² (orientada al sur, ideal para las comidas)\n— Barbacoa de carbón (carbón proporcionado en el cofre, limpien la parrilla después de usar)\n— Cancha de petanca (bolas en el cofre de madera)\n— Columpio para los niños\n— Olivos centenarios, lavanda, romero, huerto\n— Vistas a los viñedos de Châteauneuf-du-Pape\n\nPor favor, recojan los juguetes y objetos cada noche para evitar que el viento se los lleve.',6,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (88,'villa','Poubelles et recyclage','Deux types de poubelles :\n— Bac jaune : recyclables (plastique, carton, métal, papier)\n— Bac noir : ordures ménagères\n\nLe point de collecte est à 50 mètres de la maison (tourner à droite en sortant du portail).\n\nJours de collecte :\n— Bac jaune : mercredi\n— Bac noir : lundi et vendredi\n\nMerci de sortir les poubelles la veille au soir et de les rentrer après le passage.',7,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (89,'villa','Waste and recycling','Two types of bins:\n— Yellow bin: recyclables (plastic, cardboard, metal, paper)\n— Black bin: general household waste\n\nThe collection point is 50 metres from the house (turn right when leaving the gate).\n\nCollection days:\n— Yellow bin: Wednesday\n— Black bin: Monday and Friday\n\nPlease take the bins out the evening before and bring them back after collection.',7,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (90,'villa','Basura y reciclaje','Dos tipos de contenedores:\n— Contenedor amarillo: reciclables (plástico, cartón, metal, papel)\n— Contenedor negro: basura doméstica general\n\nEl punto de recogida está a 50 metros de la casa (giren a la derecha al salir del portón).\n\nDías de recogida:\n— Contenedor amarillo: miércoles\n— Contenedor negro: lunes y viernes\n\nPor favor, saquen los contenedores la noche anterior y guárdenlos después de la recogida.',7,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (91,'villa','Parking','Un parking privé gratuit est disponible dans la propriété. Vous pouvez garer jusqu\'à 3 véhicules dans l\'enceinte.\n\nSi vous venez en train : gare TGV d\'Avignon à 15 min en voiture, ou gare de Bédarrides à 10 min à pied.',8,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (92,'villa','Parking','Free private parking is available on the property. You can park up to 3 vehicles within the grounds.\n\nIf arriving by train: Avignon TGV station is 15 min by car, or Bédarrides station is a 10-minute walk.',8,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (93,'villa','Aparcamiento','Hay aparcamiento privado gratuito en la propiedad. Pueden aparcar hasta 3 vehículos dentro del recinto.\n\nSi llegan en tren: la estación TGV de Aviñón está a 15 min en coche, o la estación de Bédarrides a 10 min a pie.',8,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (94,'villa','Aux alentours','Villa Plaisance est idéalement située dans le « triangle d\'or » de la Provence :\n\n— Châteauneuf-du-Pape : 8 min (dégustations de vin)\n— Avignon : 15 min (Palais des Papes, Pont d\'Avignon)\n— Orange : 18 min (Théâtre antique romain)\n— L\'Isle-sur-la-Sorgue : 25 min (antiquaires, marché le dimanche)\n— Pont du Gard : 30 min (aqueduc romain, UNESCO)\n— Fontaine de Vaucluse : 30 min\n— Vaison-la-Romaine : 35 min\n— Gordes : 42 min (village perché)\n— Les Baux-de-Provence : 45 min (Carrières de Lumières)\n— Mont Ventoux : 45 min\n— Roussillon : 40 min (sentier des ocres)\n— Parc Spirou : 15 min (parc d\'attractions familial à Monteux)\n\nN\'hésitez pas à nous demander nos itinéraires préférés !',9,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (95,'villa','Nearby','Villa Plaisance is ideally located in Provence\'s \"golden triangle\":\n\n— Châteauneuf-du-Pape: 8 min (wine tasting)\n— Avignon: 15 min (Papal Palace, Pont d\'Avignon)\n— Orange: 18 min (Roman Theatre)\n— L\'Isle-sur-la-Sorgue: 25 min (antiques, Sunday market)\n— Pont du Gard: 30 min (Roman aqueduct, UNESCO)\n— Fontaine de Vaucluse: 30 min\n— Vaison-la-Romaine: 35 min\n— Gordes: 42 min (hilltop village)\n— Les Baux-de-Provence: 45 min (Carrières de Lumières)\n— Mont Ventoux: 45 min\n— Roussillon: 40 min (ochre trail)\n— Parc Spirou: 15 min (family theme park in Monteux)\n\nAsk us for our favourite itineraries!',9,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (96,'villa','Alrededores','Villa Plaisance está idealmente situada en el \"triángulo de oro\" de la Provenza:\n\n— Châteauneuf-du-Pape: 8 min (catas de vino)\n— Aviñón: 15 min (Palacio de los Papas, Puente de Aviñón)\n— Orange: 18 min (Teatro Romano)\n— L\'Isle-sur-la-Sorgue: 25 min (anticuarios, mercado dominical)\n— Pont du Gard: 30 min (acueducto romano, UNESCO)\n— Fontaine de Vaucluse: 30 min\n— Vaison-la-Romaine: 35 min\n— Gordes: 42 min (pueblo en la colina)\n— Les Baux-de-Provence: 45 min (Carrières de Lumières)\n— Mont Ventoux: 45 min\n— Roussillon: 40 min (sendero de los ocres)\n— Parc Spirou: 15 min (parque de atracciones familiar en Monteux)\n\n¡Pídannos nuestros itinerarios favoritos!',9,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (97,'villa','Marchés provençaux','Les marchés sont l\'âme de la Provence. Voici ceux à ne pas manquer :\n\n— Lundi : Bédarrides (petit marché local, place du village)\n— Mardi : Vaison-la-Romaine\n— Mercredi : Sorgues\n— Jeudi : Orange, Villeneuve-lès-Avignon\n— Vendredi : Carpentras (le plus grand, avec les truffes en saison)\n— Samedi : Avignon (Les Halles, marché couvert toute l\'année)\n— Dimanche : L\'Isle-sur-la-Sorgue (brocante + alimentaire, incontournable)\n\nAstuce : arrivez avant 10h et apportez vos sacs !',10,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (98,'villa','Provençal markets','Markets are the soul of Provence. Here are the must-visits:\n\n— Monday: Bédarrides (small local market, village square)\n— Tuesday: Vaison-la-Romaine\n— Wednesday: Sorgues\n— Thursday: Orange, Villeneuve-lès-Avignon\n— Friday: Carpentras (the largest, with truffles in season)\n— Saturday: Avignon (Les Halles, covered market year-round)\n— Sunday: L\'Isle-sur-la-Sorgue (antiques + food market, a must!)\n\nTip: arrive before 10am and bring your own bags!',10,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (99,'villa','Mercados provenzales','Los mercados son el alma de la Provenza. Estos son los imprescindibles:\n\n— Lunes: Bédarrides (pequeño mercado local, plaza del pueblo)\n— Martes: Vaison-la-Romaine\n— Miércoles: Sorgues\n— Jueves: Orange, Villeneuve-lès-Avignon\n— Viernes: Carpentras (el más grande, con trufas en temporada)\n— Sábado: Aviñón (Les Halles, mercado cubierto todo el año)\n— Domingo: L\'Isle-sur-la-Sorgue (antigüedades + alimentación, ¡imprescindible!)\n\nConsejo: lleguen antes de las 10:00 y lleven sus propias bolsas.',10,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (100,'villa','Restaurants que nous aimons','Voici quelques adresses testées et approuvées :\n\n— Le Numéro 3 (Bédarrides) — Bistrot au bord de l\'Ouvèze\n— Impérial Bus Diner (Sorgues) — Burgers généreux, ambiance décontractée\n— La Mère Germaine (Châteauneuf-du-Pape) — Gastronomique, vue vignes\n— Le Bercail (Avignon) — Terrasse sur l\'île de la Barthelasse\n— Christian Étienne (Avignon) — Étoilé Michelin, face au Palais\n\nPour les pizzas à emporter : [à compléter]\nPensez à réserver, surtout en juillet-août.',11,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (101,'villa','Restaurants we love','Here are some tried and tested addresses:\n\n— Le Numéro 3 (Bédarrides) — Bistro on the Ouvèze river\n— Impérial Bus Diner (Sorgues) — Generous burgers, relaxed vibe\n— La Mère Germaine (Châteauneuf-du-Pape) — Fine dining, vineyard views\n— Le Bercail (Avignon) — Terrace on Barthelasse island\n— Christian Étienne (Avignon) — Michelin-starred, facing the Palace\n\nFor takeaway pizza: [to be added]\nRemember to book, especially in July-August.',11,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (102,'villa','Restaurantes que nos gustan','Estas son algunas direcciones probadas y aprobadas:\n\n— Le Numéro 3 (Bédarrides) — Bistró a orillas del Ouvèze\n— Impérial Bus Diner (Sorgues) — Hamburguesas generosas, ambiente relajado\n— La Mère Germaine (Châteauneuf-du-Pape) — Gastronómico, vistas a viñedos\n— Le Bercail (Aviñón) — Terraza en la isla de la Barthelasse\n— Christian Étienne (Aviñón) — Estrella Michelin, frente al Palacio\n\nPara pizza para llevar: [por añadir]\nRecuerden reservar, especialmente en julio-agosto.',11,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (103,'villa','Numéros utiles','Urgences : 112 (européen) / 15 (SAMU) / 18 (pompiers)\nPolice : 17\nPharmacies de garde : 3237\n\nHôpital le plus proche : Centre Hospitalier d\'Avignon — 20 min\nAdresse : 305 Rue Raoul Follereau, 84000 Avignon\n\nPharmacie Bédarrides : Place de la Mairie\nMédecin Bédarrides : Cabinet médical, rue de la République\nVétérinaire (si vous voyagez avec un animal) : Clinique de Sorgues — 10 min\n\nVos hôtes : joignables par téléphone ou via le formulaire en bas de cette page.',12,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (104,'villa','Useful numbers','Emergencies: 112 (European) / 15 (ambulance) / 18 (fire)\nPolice: 17\nOn-call pharmacies: 3237\n\nNearest hospital: Centre Hospitalier d\'Avignon — 20 min\nAddress: 305 Rue Raoul Follereau, 84000 Avignon\n\nBédarrides pharmacy: Place de la Mairie\nBédarrides doctor: Medical practice, rue de la République\nVet (if travelling with a pet): Sorgues clinic — 10 min\n\nYour hosts: reachable by phone or via the form at the bottom of this page.',12,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (105,'villa','Números útiles','Urgencias: 112 (europeo) / 15 (ambulancia) / 18 (bomberos)\nPolicía: 17\nFarmacias de guardia: 3237\n\nHospital más cercano: Centre Hospitalier d\'Avignon — 20 min\nDirección: 305 Rue Raoul Follereau, 84000 Avignon\n\nFarmacia Bédarrides: Place de la Mairie\nMédico Bédarrides: Consultorio médico, rue de la République\nVeterinario (si viajan con mascota): Clínica de Sorgues — 10 min\n\nSus anfitriones: contactables por teléfono o mediante el formulario al final de esta página.',12,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (106,'villa','Départ','Le départ se fait le samedi avant 10h.\n\nMerci de :\n— Lancer un dernier cycle de lave-vaisselle\n— Vider le réfrigérateur (poubelle noire pour les déchets)\n— Rassembler les draps et serviettes usagés au pied de chaque lit\n— Fermer toutes les fenêtres et volets\n— Éteindre la climatisation dans chaque pièce\n— Laisser les clés sur la table de la cuisine\n— Refermer le portail en partant\n\nUn état des lieux sera fait après votre départ.\n\nMerci pour votre séjour et n\'oubliez pas de nous laisser un avis ! À bientôt en Provence.',13,1,'fr','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (107,'villa','Checkout','Checkout is on Saturday before 10am.\n\nPlease:\n— Run a final dishwasher cycle\n— Empty the fridge (black bin for waste)\n— Gather used sheets and towels at the foot of each bed\n— Close all windows and shutters\n— Turn off air conditioning in every room\n— Leave the keys on the kitchen table\n— Close the gate when leaving\n\nAn inventory check will be carried out after your departure.\n\nThank you for your stay and don\'t forget to leave us a review! See you again in Provence.',13,1,'en','2026-03-30 13:32:27','2026-03-30 13:32:27');
INSERT INTO `vp_livret` (`id`, `type`, `section_title`, `content`, `position`, `active`, `lang`, `created_at`, `updated_at`) VALUES (108,'villa','Salida','La salida es el sábado antes de las 10:00.\n\nPor favor:\n— Pongan un último ciclo de lavavajillas\n— Vacíen el frigorífico (contenedor negro para los desechos)\n— Junten las sábanas y toallas usadas al pie de cada cama\n— Cierren todas las ventanas y persianas\n— Apaguen el aire acondicionado en cada habitación\n— Dejen las llaves en la mesa de la cocina\n— Cierren el portón al salir\n\nSe realizará un inventario después de su partida.\n\nGracias por su estancia y ¡no olviden dejarnos una reseña! Hasta pronto en Provenza.',13,1,'es','2026-03-30 13:32:27','2026-03-30 13:32:27');
