INSERT INTO `vp_pieces` (`id`, `offer`, `type`, `position`, `name`, `sous_titre`, `description`, `equip`, `note`, `image`, `images`, `css_class`, `lang`, `created_at`) VALUES (20,'villa','chambre',4,'Habitación 70','Mobiliario vintage años 70','Cama doble, mobiliario vintage de los años 70. Acceso directo al jardín por una puerta-ventana. La habitación más singular de la villa.','Cama doble, Mobiliario vintage, Acceso directo jardín, Aire acond.','Acceso directo al jardín','villa-plaisance-chambre-annees-70-03.webp','[\"villa-plaisance-chambre-annees-70-03.webp\",\"villa-plaisance-chambre-annees-70-05.webp\",\"villa-plaisance-chambre-annees-70-04.webp\",\"villa-plaisance-chambre-annees-70-07.webp\"]','','es','2026-03-30 10:04:32');
