INSERT INTO `vp_reviews` (`id`, `platform`, `offer`, `author`, `origin`, `content`, `rating`, `review_date`, `featured`, `home_carousel`, `status`, `created_at`) VALUES (107,'google','bb','RUGBY A 5','','Tout était parfait, de l\'accueil au confort au petit déjeuner. Établissement plus propre qu\'un hôtel, cadre super. Jorge est un hôte exceptionnel.',5.0,'2025-04-01',0,0,'published','2026-03-30 12:23:20');
INSERT INTO `vp_reviews` (`id`, `platform`, `offer`, `author`, `origin`, `content`, `rating`, `review_date`, `featured`, `home_carousel`, `status`, `created_at`) VALUES (108,'google','bb','Bruno DHL','','Super accueil de Jorge et un petit déjeuner excellent !!!! Au calme malgré la proximité de l\'autoroute. Belle villa avec piscine.',5.0,'2025-04-01',0,0,'published','2026-03-30 12:23:20');
INSERT INTO `vp_reviews` (`id`, `platform`, `offer`, `author`, `origin`, `content`, `rating`, `review_date`, `featured`, `home_carousel`, `status`, `created_at`) VALUES (109,'google','bb','Laurence Papoutchian','','Nous avons passé un très bon séjour dans cette maison d\'hôte. Le lieu est agréable et l\'accueil sympathique et chaleureux. Nous recommandons cette adresse.',5.0,'2022-05-01',0,0,'published','2026-03-30 12:23:20');
INSERT INTO `vp_reviews` (`id`, `platform`, `offer`, `author`, `origin`, `content`, `rating`, `review_date`, `featured`, `home_carousel`, `status`, `created_at`) VALUES (110,'google','bb','Christel Joliveau','','Séjour très agréable et petit déjeuner au top. La brioche perdue !',5.0,'2025-04-01',0,0,'published','2026-03-30 12:23:20');
INSERT INTO `vp_reviews` (`id`, `platform`, `offer`, `author`, `origin`, `content`, `rating`, `review_date`, `featured`, `home_carousel`, `status`, `created_at`) VALUES (111,'google','bb','Achim Donald','','Jorge, notre hôte, nous a donné de précieux conseils et a partagé avec nous une connaissance approfondie des lieux que nous avons visités. Un accueil exceptionnel ! Nous nous sommes sentis comme chez nous.',5.0,'2025-04-01',0,0,'published','2026-03-30 12:23:20');
INSERT INTO `vp_reviews` (`id`, `platform`, `offer`, `author`, `origin`, `content`, `rating`, `review_date`, `featured`, `home_carousel`, `status`, `created_at`) VALUES (112,'google','bb','Enyrd Weis','','Séjour merveilleux à la Villa Plaisance ! J\'ai particulièrement apprécié le petit-déjeuner copieux, la piscine et les échanges agréables avec les hôtes. Je recommande vivement !',5.0,'2022-05-01',0,0,'published','2026-03-30 12:23:20');
INSERT INTO `vp_reviews` (`id`, `platform`, `offer`, `author`, `origin`, `content`, `rating`, `review_date`, `featured`, `home_carousel`, `status`, `created_at`) VALUES (113,'google','bb','Raphaël Saunier','','',5.0,'2022-10-01',0,0,'published','2026-03-30 12:23:20');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (2,'accueil','fr','hero','Hero accueil','{\"title\":\"Villa Plaisance — Chambres d\'hôtes & villa privée en Provence\",\"subtitle\":\"Bédarrides, au cœur du Triangle d\'Or · 9.4\\/10 Booking · Superhost Airbnb\",\"cta_text\":\"Vérifier les disponibilités\",\"cta_url\":\"\\/contact\",\"image\":[\"villa-plaisance-piscine-privee-05.webp\",\"villa-plaisance-piscine-privee-09.webp\",\"villa-plaisance-jardin-exterieur-15.webp\"],\"image_alt\":\"Villa Plaisance, maison d\'hôtes de charme à Bédarrides en Provence\",\"compact\":\"0\"}',1,1,'2026-03-29 15:03:08','2026-03-29 22:31:38');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (3,'accueil','fr','prose','Identité','{\"heading\":\"Une maison, deux façons d\'y séjourner\",\"text\":\"Nichée au cœur du Triangle d\'Or provençal, Villa Plaisance est une maison de charme à Bédarrides — à 15 min d\'Avignon, 8 min de Châteauneuf-du-Pape, 18 min d\'Orange. De septembre à juin : chambres d\'hôtes B&B avec petit-déjeuner maison et piscine partagée. En juillet-août : la villa entière (4 chambres, 10 personnes, piscine privée 12×6 m) en toute autonomie. Le lieu est calme, le village vivant, la campagne à pied, le TGV à quinze minutes.\",\"image\":\"villa-plaisance-facade-01.webp\",\"image_alt\":\"Reflet de Villa Plaisance dans la piscine — Bédarrides, Provence\",\"lead\":\"0\"}',2,1,'2026-03-29 15:03:08','2026-03-29 19:27:08');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (4,'accueil','fr','stats','Chiffres clés','{}',3,1,'2026-03-29 15:03:08','2026-03-29 15:03:08');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (5,'accueil','fr','prose','Offre Chambres d\'hôtes','{\"heading\":\"Chambres d\'hôtes — de septembre à juin\",\"text\":\"Vous séjournez chez l\'habitant. Deux chambres communicantes et climatisées avec salle de bain privée vous sont strictement dédiées. Le petit-déjeuner est inclus : produits locaux, confitures maison, fruits du jardin. Piscine partagée, conseils personnalisés et accueil chaleureux. Suite communicante idéale pour les familles (1 à 5 personnes).\",\"image\":\"villa-plaisance-chambre-verte-01.webp\",\"image_alt\":\"Chambre Verte, chambre d\'hôtes — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',4,1,'2026-03-29 15:03:08','2026-03-29 19:27:24');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (6,'accueil','fr','prose','Offre Villa entière','{\"heading\":\"La Villa en exclusivité — juillet & août\",\"text\":\"Vous séjournez seuls et disposez de la villa et des extérieurs en exclusivité. 4 chambres, 2 salles de bain, cuisine entièrement équipée, piscine privée clôturée 12×6 m et jardin sous les oliviers. Jusqu\'à 10 personnes en totale autonomie — votre maison en Provence, sans vis-à-vis.\",\"image\":\"villa-plaisance-piscine-privee-09.webp\",\"image_alt\":\"Piscine privée 12×6 m clôturée — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',5,1,'2026-03-29 15:03:08','2026-03-29 19:27:46');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (7,'accueil','fr','territoire','Triangle d\'Or','{\"heading\":\"Au cœur du Triangle d\'Or\"}',6,1,'2026-03-29 15:03:08','2026-03-29 15:03:08');
