INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (11,'accueil','fr','cta','CTA Contact','{\"heading\": \"Votre séjour en Provence commence ici\", \"text\": \"Choisissez l\'offre qui vous correspond et réservez en quelques clics. Réservation directe = meilleur tarif garanti.\", \"button_text\": \"Vérifier les disponibilités\", \"button_url\": \"/contact\", \"dark\": true}',11,1,'2026-03-29 15:03:08','2026-03-30 12:44:41');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (12,'chambres-d-hotes','fr','hero','Hero Chambres','{\"title\":\"Chambres d\'hôtes — Votre parenthèse provençale\",\"subtitle\":\"Deux chambres privatives avec petit-déjeuner · De septembre à juin · Note 9.4\\/10\",\"cta_text\":\"Réserver votre séjour\",\"cta_url\":\"\\/contact\",\"image\":[\"villa-plaisance-chambre-verte-02.webp\",\"villa-plaisance-chambre-bleue-05.webp\",\"villa-plaisance-chambre-bleue-07.webp\"],\"image_alt\":\"Chambres d\'hôtes Villa Plaisance à Bédarrides\",\"compact\":\"0\"}',1,1,'2026-03-29 15:03:08','2026-03-29 22:32:03');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (13,'chambres-d-hotes','fr','prose','Intro Chambres','{\"heading\":\"Chambres d\'hôtes B&B à Bédarrides\",\"text\":\"À Villa Plaisance, nous accueillons nos hôtes de septembre à juin dans deux chambres de charme pensées pour le confort et l\'authenticité provençale. Petit-déjeuner maison, piscine partagée, jardins ombragés — une adresse intime à 15 min d\'Avignon et 8 min de Châteauneuf-du-Pape.\",\"image\":\"villa-plaisance-chambre-bleue-05.webp\",\"image_alt\":\"\",\"lead\":\"1\"}',2,1,'2026-03-29 15:03:08','2026-03-29 19:29:26');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (14,'chambres-d-hotes','fr','cartes','Chambres BB','{\"offer\":\"bb\"}',3,1,'2026-03-29 15:03:08','2026-03-29 15:03:08');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (15,'chambres-d-hotes','fr','petit-dejeuner','Petit-déjeuner','{\"heading\":\"Petit-déjeuner maison inclus\",\"text\":\"Chaque matin, de 7h30 à 10h, en terrasse ou en véranda selon la saison. Confitures artisanales (figues, abricots, lavande-miel), viennoiseries, pain de boulanger, fromages provençaux, charcuterie régionale, fruits frais de saison, jus d\'orange pressé, café, thé et tisanes bio, miel et yaourt maison.\",\"image\":[\"villa-plaisance-petit-dejeuner-brioche-01.webp\",\"villa-plaisance-petit-dejeuner-confitures-01.webp\",\"villa-plaisance-petit-dejeuner-fruits-01.webp\"],\"image_alt\":\"Petit-déjeuner maison servi en terrasse — Villa Plaisance, Bédarrides\"}',4,1,'2026-03-29 15:03:08','2026-03-29 22:48:34');
