INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (18,'location-villa-provence','fr','hero','Hero Villa','{\"title\":\"La Villa entière — Rien que pour vous\",\"subtitle\":\"4 chambres · Piscine privée 12×6 m · Jusqu\'à 10 personnes · Juillet & août\",\"cta_text\":\"Réserver la villa\",\"cta_url\":\"\\/contact\",\"image\":[\"villa-plaisance-piscine-privee-03.webp\",\"villa-plaisance-jardin-exterieur-21.webp\",\"villa-plaisance-facade-04.webp\",\"villa-plaisance-detail-decoration-03.webp\"],\"image_alt\":\"Villa Plaisance en exclusivité avec piscine privée et jardin provençal\",\"compact\":\"0\"}',1,1,'2026-03-29 15:03:08','2026-03-29 22:33:26');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (19,'location-villa-provence','fr','prose','Intro Villa','{\"heading\": \"La villa entière en toute autonomie\", \"text\": \"En juillet et en août, Villa Plaisance ouvre ses portes en location complète. Quatre chambres, dix personnes, une piscine privée exclusive, une grande cuisine équipée et des terrasses face aux vignes — une maison de famille à Bédarrides, à 15 min d\'Avignon et 8 min de Châteauneuf-du-Pape. La gestion est autonome, les clés sont à vous.\", \"lead\": true}',2,1,'2026-03-29 15:03:08','2026-03-29 18:00:45');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (20,'location-villa-provence','fr','cartes','Chambres Villa','{\"offer\":\"villa\"}',3,1,'2026-03-29 15:03:08','2026-03-29 15:03:08');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (21,'location-villa-provence','fr','piscine','Piscine','{\"heading\":\"Piscine privée et clôturée 12×6 m\",\"text\":\"Exclusivement réservée à votre groupe, 24h\\/24. Transats, parasols, table de jardin, salon extérieur et douche solaire. La piscine peut être chauffée sur demande. Aucune autre famille ou locataire n\'y a accès pendant votre séjour.\",\"image\":[\"villa-plaisance-piscine-privee-03.webp\",\"villa-plaisance-piscine-privee-07.webp\",\"villa-plaisance-piscine-privee-08.webp\"],\"image_alt\":\"Piscine privée clôturée 12×6 m — Villa Plaisance, Bédarrides\"}',4,1,'2026-03-29 15:03:08','2026-03-29 22:50:47');
