INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (23,'location-villa-provence','fr','cta','CTA Villa','{\"heading\": \"Votre été en Provence commence ici\", \"text\": \"Réservez votre semaine en toute sécurité ou contactez-nous pour un devis personnalisé. Réservation directe = meilleur tarif garanti.\", \"button_text\": \"Vérifier les disponibilités\", \"button_url\": \"/contact\", \"dark\": true}',9,1,'2026-03-29 15:03:08','2026-03-29 18:00:45');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (24,'espaces-exterieurs','fr','hero','Hero Extérieurs','{\"title\":\"Jardin, piscine & terrasses — Le charme en plein air\",\"subtitle\":\"1 500 m² de verdure, piscine clôturée, terrasse ombragée et vignes à perte de vue\",\"cta_text\":\"\",\"cta_url\":\"\",\"image\":[\"villa-plaisance-chambre-annees-70-11.webp\",\"villa-plaisance-jardin-exterieur-06.webp\"],\"image_alt\":\"Jardin provençal et piscine de Villa Plaisance à Bédarrides\",\"compact\":\"0\"}',1,1,'2026-03-29 15:03:08','2026-03-29 22:33:56');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (25,'espaces-exterieurs','fr','prose','Intro Extérieurs','{\"heading\":\"Dehors, ici, c\'est encore chez vous\",\"text\":\"Le jardin de Villa Plaisance est un prolongement naturel de la maison. 1 500 m² de verdure, oliviers centenaires, lavandes, rosiers anciens et herbes aromatiques (thym, romarin, basilic, menthe fraîche). La piscine de 12 mètres sur 6, les terrasses ombragées, le potager en été. Un espace où l\'on passe plus de temps qu\'à l\'intérieur — entre les cigales et les premiers rayons du soleil.\",\"image\":[\"villa-plaisance-facade-11.webp\",\"villa-plaisance-jardin-exterieur-09.webp\",\"villa-plaisance-jardin-exterieur-15.webp\"],\"image_alt\":\"\",\"lead\":\"1\"}',2,1,'2026-03-29 15:03:08','2026-03-29 22:51:48');
