INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (27,'espaces-exterieurs','fr','cta','CTA Extérieurs','{\"heading\": \"Profitez des extérieurs en Provence\", \"text\": \"Chambres d\'hôtes (sept–juin) ou villa entière (juil–août) — les extérieurs sont toujours inclus. Réservation directe = meilleur tarif garanti.\", \"button_text\": \"Vérifier les disponibilités\", \"button_url\": \"/contact\", \"dark\": true}',8,1,'2026-03-29 15:03:08','2026-03-29 18:06:14');
