INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (31,'chambres-d-hotes','fr','liste','Équipements chambres','{\"heading\": \"Équipements & services inclus\", \"style\": \"check\", \"items\": [\"Literie premium (draps 100 % coton percale)\", \"Salle de bain privative avec produits de toilette bio\", \"Climatisation réversible dans chaque chambre\", \"Wifi haut débit gratuit\", \"Télévision écran plat\", \"Piscine partagée 12×6 m (mai à octobre)\", \"Jardin provençal et terrasses ombragées\", \"Parking privé gratuit\", \"Arrivée autonome (boîte à clé)\", \"Conseils et recommandations locales personnalisés\"]}',5,1,'2026-03-29 17:59:51','2026-03-29 17:59:51');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (32,'chambres-d-hotes','fr','tableau','Infos pratiques chambres','{\"heading\": \"Informations pratiques\", \"rows\": [{\"label\": \"Période\", \"value\": \"De septembre à juin\"}, {\"label\": \"Arrivée\", \"value\": \"À partir de 17h\"}, {\"label\": \"Départ\", \"value\": \"Avant 11h\"}, {\"label\": \"Séjour minimum\", \"value\": \"2 nuits (haute saison : 3 nuits)\"}, {\"label\": \"Capacité\", \"value\": \"1 à 5 personnes (suite communicante)\"}, {\"label\": \"Petit-déjeuner\", \"value\": \"Inclus · servi de 7h30 à 10h\"}, {\"label\": \"Piscine\", \"value\": \"Partagée · 12×6 m · mai à octobre\"}, {\"label\": \"Animaux\", \"value\": \"Non acceptés\"}, {\"label\": \"Fumeur\", \"value\": \"Non-fumeur\"}]}',6,1,'2026-03-29 17:59:51','2026-03-29 17:59:51');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (33,'location-villa-provence','fr','liste','Espaces villa','{\"heading\": \"Les espaces de la villa\", \"style\": \"check\", \"items\": [\"Suite parentale : lit king 180×200 + salle de bain privée + dressing + vue jardin\", \"Chambre Bleue : lit double queen 160×200\", \"Chambre de l\'Arche : lit double 160×200\", \"Chambre Années 70 : 2 lits simples 90×200 (jumelables)\", \"2 salles de bain complètes + 3 WC indépendants\", \"Grand salon et salle à manger climatisés\", \"Cuisine équipée : piano gaz, lave-vaisselle, réfrigérateur XXL, four, micro-ondes\", \"Terrasse couverte 40 m² avec salon de jardin 12 places\", \"Jardin provençal avec oliviers, BBQ charbon et terrain de pétanque\", \"Lave-linge et sèche-linge\", \"Wifi haut débit (fibre) + TV streaming dans chaque pièce de vie\", \"Parking fermé 2 véhicules\", \"Lit bébé et chaise haute disponibles sur demande\"]}',5,1,'2026-03-29 18:00:45','2026-03-29 18:00:45');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (34,'location-villa-provence','fr','tableau','Infos pratiques villa','{\"heading\": \"Informations pratiques\", \"rows\": [{\"label\": \"Période\", \"value\": \"Juillet et août uniquement\"}, {\"label\": \"Arrivée\", \"value\": \"À partir de 17h\"}, {\"label\": \"Départ\", \"value\": \"Avant 10h\"}, {\"label\": \"Séjour minimum\", \"value\": \"7 nuits (samedi → samedi)\"}, {\"label\": \"Capacité\", \"value\": \"10 personnes max · 4 chambres\"}, {\"label\": \"Piscine\", \"value\": \"Privée exclusive · 12×6 m · chauffage en option\"}, {\"label\": \"Ménage\", \"value\": \"Fin de séjour inclus · Intermédiaire en option\"}, {\"label\": \"Animaux\", \"value\": \"Non acceptés\"}, {\"label\": \"Fumeur\", \"value\": \"Non-fumeur\"}, {\"label\": \"Linge\", \"value\": \"Draps et serviettes fournis\"}]}',6,1,'2026-03-29 18:00:45','2026-03-29 18:00:45');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (35,'espaces-exterieurs','fr','prose','Piscine extérieurs','{\"heading\":\"Piscine 12×6 m — clôturée et sécurisée\",\"text\":\"Le bassin mesure 12 mètres sur 6, entièrement clôturé pour la sécurité des enfants. Transats, parasols, douche solaire et salon de jardin sont à disposition. En chambres d\'hôtes (sept–juin) : piscine partagée, accessible de 9h à 21h. En villa entière (juil–août) : piscine privée exclusive, 24h\\/24. Chauffage disponible sur demande.\",\"image\":[\"villa-plaisance-jardin-exterieur-04.webp\",\"villa-plaisance-piscine-privee-01.webp\",\"villa-plaisance-piscine-privee-05.webp\"],\"image_alt\":\"Piscine clôturée 12×6 m — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',3,1,'2026-03-29 18:06:14','2026-03-29 22:52:47');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (36,'espaces-exterieurs','fr','prose','Terrasses extérieurs','{\"heading\":\"Terrasses ombragées face aux vignes\",\"text\":\"Terrasse couverte de 40 m² orientée sud, parfaite pour les repas en plein air, les apéritifs face aux vignes et les soirées jusqu\'à la tombée de la nuit. Salon de jardin 12 places, véranda de lecture pour les matinées calmes. Le petit-déjeuner y est servi chaque matin (en saison B&B).\",\"image\":[\"villa-plaisance-chambre-annees-70-11.webp\",\"villa-plaisance-facade-11.webp\",\"villa-plaisance-jardin-exterieur-05.webp\"],\"image_alt\":\"Terrasse ombragée orientée sud — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',4,1,'2026-03-29 18:06:14','2026-03-29 22:53:18');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (37,'espaces-exterieurs','fr','prose','Jardin extérieurs','{\"heading\":\"Jardin provençal — oliviers, lavandes et herbes aromatiques\",\"text\":\"Un jardin arboré planté d\'oliviers centenaires, de lavandes, de rosiers anciens et d\'herbes aromatiques. Espace BBQ charbon avec table 12 couverts, terrain de pétanque sous les arbres, aire de jeux pour les enfants. Les vignes de Châteauneuf-du-Pape commencent au bout du chemin.\",\"image\":[\"villa-plaisance-piscine-privee-06.webp\",\"villa-plaisance-jardin-exterieur-20.webp\",\"villa-plaisance-jardin-exterieur-09.webp\"],\"image_alt\":\"Jardin provençal avec oliviers centenaires — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',5,1,'2026-03-29 18:06:14','2026-03-29 22:53:59');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (38,'espaces-exterieurs','fr','liste','Équipements extérieurs','{\"heading\": \"Équipements extérieurs\", \"style\": \"check\", \"items\": [\"Piscine 12×6 m clôturée (partagée ou privée selon offre)\", \"Chauffage piscine disponible sur demande\", \"Transats, parasols et douche solaire\", \"Terrasse couverte 40 m² orientée sud\", \"Salon de jardin 12 places\", \"BBQ charbon + table extérieure 12 couverts\", \"Terrain de pétanque\", \"Aire de jeux enfants\", \"Jardin arboré (oliviers, lavandes, romarin)\", \"Potager en été (herbes aromatiques en libre-service)\", \"Parking privé gratuit\", \"Éclairage extérieur pour les soirées\"]}',6,1,'2026-03-29 18:06:14','2026-03-29 18:06:14');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (39,'accueil','en','hero','Hero Home','{\"title\":\"Villa Plaisance — B&B & Private Villa in Provence\",\"subtitle\":\"Bédarrides, in the heart of the Golden Triangle · 9.4\\/10 Booking · Superhost Airbnb\",\"buttons\":[{\"text\":\"Check availability\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"image\":[\"villa-plaisance-piscine-privee-05.webp\",\"villa-plaisance-piscine-privee-09.webp\",\"villa-plaisance-jardin-exterieur-15.webp\"],\"image_alt\":\"Villa Plaisance, maison d\'hôtes de charme à Bédarrides en Provence\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (40,'accueil','es','hero','Hero Inicio','{\"title\":\"Villa Plaisance — B&B y Villa privada en Provenza\",\"subtitle\":\"Bédarrides, en el corazón del Triángulo de Oro · 9,4\\/10 Booking · Superhost Airbnb\",\"buttons\":[{\"text\":\"Consultar disponibilidad\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"image\":[\"villa-plaisance-piscine-privee-05.webp\",\"villa-plaisance-piscine-privee-09.webp\",\"villa-plaisance-jardin-exterieur-15.webp\"],\"image_alt\":\"Villa Plaisance, maison d\'hôtes de charme à Bédarrides en Provence\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (41,'accueil','en','prose','Identity','{\"heading\":\"One house, two ways to stay\",\"text\":\"Nestled in the heart of Provence\'s Golden Triangle, Villa Plaisance is a charming house in Bédarrides — 15 min from Avignon, 8 min from Châteauneuf-du-Pape, 18 min from Orange. From September to June, we welcome guests in B&B rooms with homemade breakfast and shared pool. In July and August, the entire villa is yours exclusively: four bedrooms, a private 12×6 m pool, a garden beneath the olive trees. The place is peaceful. The village is lively. The countryside is on foot, the TGV 15 minutes away.\",\"image\":\"villa-plaisance-facade-01.webp\",\"image_alt\":\"Reflet de Villa Plaisance dans la piscine — Bédarrides, Provence\",\"lead\":\"0\"}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (42,'accueil','es','prose','Identidad','{\"heading\":\"Una casa, dos formas de alojarse\",\"text\":\"En el corazón del Triángulo de Oro provenzal, Villa Plaisance es una casa con encanto en Bédarrides — a 15 min de Aviñón, 8 min de Châteauneuf-du-Pape, 18 min de Orange. De septiembre a junio, recibimos huéspedes en habitaciones B&B con desayuno casero y piscina compartida. En julio y agosto, la villa entera es suya en exclusiva: cuatro habitaciones, piscina privada de 12×6 m, jardín bajo los olivos.\",\"image\":\"villa-plaisance-facade-01.webp\",\"image_alt\":\"Reflet de Villa Plaisance dans la piscine — Bédarrides, Provence\",\"lead\":\"0\"}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (43,'accueil','en','stats','Chiffres clés','{}',3,1,'2026-03-30 09:50:37','2026-03-30 09:50:37');
