INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (45,'accueil','en','prose','B&B Offer','{\"heading\":\"Bed & Breakfast — September to June\",\"text\":\"You stay in our home. Two connecting, air-conditioned rooms with private bathroom are exclusively yours: the Green Room and the Blue Room. Homemade breakfast, shared pool, and our recommendations for the area. The charm of Provence without the hassle of planning.\",\"image\":\"villa-plaisance-chambre-verte-01.webp\",\"image_alt\":\"Chambre Verte, chambre d\'hôtes — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',4,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (46,'accueil','es','prose','Oferta B&B','{\"heading\":\"B&B — de septiembre a junio\",\"text\":\"Se aloja en nuestra casa. Dos habitaciones comunicantes y climatizadas con baño privado son exclusivamente suyas: la Habitación Verde y la Habitación Azul. Desayuno casero, piscina compartida y nuestras recomendaciones de la zona.\",\"image\":\"villa-plaisance-chambre-verte-01.webp\",\"image_alt\":\"Chambre Verte, chambre d\'hôtes — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',4,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (47,'accueil','en','prose','Villa Offer','{\"heading\":\"The Villa exclusively — July & August\",\"text\":\"You have the villa and grounds all to yourselves. 4 bedrooms, 2 bathrooms, fully equipped kitchen, shaded terrace and private 12×6 m pool. Ideal for a family holiday or a group of friends up to 10 people.\",\"image\":\"villa-plaisance-piscine-privee-09.webp\",\"image_alt\":\"Piscine privée 12×6 m clôturée — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',5,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (48,'accueil','es','prose','Oferta Villa','{\"heading\":\"La Villa en exclusiva — julio y agosto\",\"text\":\"Dispone de la villa y los exteriores en exclusiva. 4 habitaciones, 2 baños, cocina equipada, terraza sombreada y piscina privada de 12×6 m. Ideal para vacaciones familiares o un grupo de amigos de hasta 10 personas.\",\"image\":\"villa-plaisance-piscine-privee-09.webp\",\"image_alt\":\"Piscine privée 12×6 m clôturée — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',5,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
