INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (57,'accueil','en','cta','CTA Contact','{\"heading\":\"Your stay in Provence starts here\",\"text\":\"Choose the option that suits you and book in a few clicks. Direct booking = best rate guaranteed.\",\"buttons\":[{\"text\":\"Check availability\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"dark\":true,\"button_url\":\"\\/contact\"}',10,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (58,'accueil','es','cta','CTA Contacto','{\"heading\":\"Su estancia en Provenza empieza aquí\",\"text\":\"Elija la opción que más le convenga y reserve en pocos clics. Reserva directa = mejor tarifa garantizada.\",\"buttons\":[{\"text\":\"Consultar disponibilidad\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"dark\":true,\"button_url\":\"\\/contact\"}',10,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (59,'chambres-d-hotes','en','hero','Hero Rooms','{\"title\":\"Bed & Breakfast — Your Provençal retreat\",\"subtitle\":\"Two private rooms with breakfast · September to June · Rated 9.4\\/10\",\"buttons\":[{\"text\":\"Book your stay\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"image\":[\"villa-plaisance-chambre-verte-02.webp\",\"villa-plaisance-chambre-bleue-05.webp\",\"villa-plaisance-chambre-bleue-07.webp\"],\"image_alt\":\"Chambres d\'hôtes Villa Plaisance à Bédarrides\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (60,'chambres-d-hotes','es','hero','Hero Habitaciones','{\"title\":\"B&B — Su retiro provenzal\",\"subtitle\":\"Dos habitaciones privadas con desayuno · De septiembre a junio · Nota 9,4\\/10\",\"buttons\":[{\"text\":\"Reservar su estancia\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"image\":[\"villa-plaisance-chambre-verte-02.webp\",\"villa-plaisance-chambre-bleue-05.webp\",\"villa-plaisance-chambre-bleue-07.webp\"],\"image_alt\":\"Chambres d\'hôtes Villa Plaisance à Bédarrides\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (61,'chambres-d-hotes','en','prose','Intro Rooms','{\"heading\":\"B&B in Bédarrides\",\"text\":\"At Villa Plaisance, we welcome guests from September to June in two charming rooms designed for comfort and tranquillity. Each room has its own private bathroom, air conditioning, and Wi-Fi. Homemade breakfast is served every morning on the terrace or in the veranda. The shared pool is available from May to October.\",\"image\":\"villa-plaisance-chambre-bleue-05.webp\",\"image_alt\":\"\",\"lead\":\"1\"}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (62,'chambres-d-hotes','es','prose','Intro Habitaciones','{\"heading\":\"B&B en Bédarrides\",\"text\":\"En Villa Plaisance, recibimos huéspedes de septiembre a junio en dos habitaciones con encanto diseñadas para el confort y la tranquilidad. Cada habitación tiene baño privado, aire acondicionado y Wi-Fi. El desayuno casero se sirve cada mañana en la terraza o en la galería.\",\"image\":\"villa-plaisance-chambre-bleue-05.webp\",\"image_alt\":\"\",\"lead\":\"1\"}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
