INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (65,'chambres-d-hotes','en','petit-dejeuner','Breakfast','{\"heading\":\"Homemade breakfast included\",\"text\":\"Every morning from 7:30 to 10:00, on the terrace or in the veranda depending on the season. Artisanal jams (figs, apricots, lavender), fresh bread, pastries, seasonal fruit, cheeses, eggs from the garden, juice, coffee, tea.\",\"image\":[\"villa-plaisance-petit-dejeuner-brioche-01.webp\",\"villa-plaisance-petit-dejeuner-confitures-01.webp\",\"villa-plaisance-petit-dejeuner-fruits-01.webp\"],\"image_alt\":\"Petit-déjeuner maison servi en terrasse — Villa Plaisance, Bédarrides\"}',4,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (66,'chambres-d-hotes','es','petit-dejeuner','Desayuno','{\"heading\":\"Desayuno casero incluido\",\"text\":\"Cada mañana de 7:30 a 10:00, en la terraza o en la galería según la temporada. Mermeladas artesanales (higos, albaricoques, lavanda), pan fresco, bollería, fruta de temporada, quesos, huevos del jardín, zumo, café, té.\",\"image\":[\"villa-plaisance-petit-dejeuner-brioche-01.webp\",\"villa-plaisance-petit-dejeuner-confitures-01.webp\",\"villa-plaisance-petit-dejeuner-fruits-01.webp\"],\"image_alt\":\"Petit-déjeuner maison servi en terrasse — Villa Plaisance, Bédarrides\"}',4,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
