INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (77,'espaces-exterieurs','en','hero','Hero Outdoors','{\"title\":\"Garden, Pool & Terraces — Outdoor charm\",\"subtitle\":\"1,500 m² of greenery, fenced pool, shaded terrace and vineyard views\",\"image\":[\"villa-plaisance-chambre-annees-70-11.webp\",\"villa-plaisance-jardin-exterieur-06.webp\"],\"image_alt\":\"Jardin provençal et piscine de Villa Plaisance à Bédarrides\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (78,'espaces-exterieurs','es','hero','Hero Exteriores','{\"title\":\"Jardín, piscina y terrazas — Encanto al aire libre\",\"subtitle\":\"1.500 m² de vegetación, piscina vallada, terraza sombreada y vistas a los viñedos\",\"image\":[\"villa-plaisance-chambre-annees-70-11.webp\",\"villa-plaisance-jardin-exterieur-06.webp\"],\"image_alt\":\"Jardin provençal et piscine de Villa Plaisance à Bédarrides\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (79,'espaces-exterieurs','en','prose','Intro Outdoors','{\"heading\":\"Outside, you\'re still at home\",\"text\":\"Villa Plaisance\'s garden is a natural extension of the house. 1,500 m² of greenery, century-old olive trees, lavender, rosemary, a vegetable garden in summer. The fenced pool overlooks the vineyards. The shaded terrace is where everything happens: breakfast, aperitifs, dinner under the stars.\",\"image\":[\"villa-plaisance-facade-11.webp\",\"villa-plaisance-jardin-exterieur-09.webp\",\"villa-plaisance-jardin-exterieur-15.webp\"],\"image_alt\":\"\",\"lead\":\"1\"}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (80,'espaces-exterieurs','es','prose','Intro Exteriores','{\"heading\":\"Fuera, sigue siendo su casa\",\"text\":\"El jardín de Villa Plaisance es una extensión natural de la casa. 1.500 m² de vegetación, olivos centenarios, lavanda, romero, huerto en verano. La piscina vallada da a los viñedos. La terraza sombreada es donde todo sucede: desayuno, aperitivos, cena bajo las estrellas.\",\"image\":[\"villa-plaisance-facade-11.webp\",\"villa-plaisance-jardin-exterieur-09.webp\",\"villa-plaisance-jardin-exterieur-15.webp\"],\"image_alt\":\"\",\"lead\":\"1\"}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (81,'espaces-exterieurs','en','prose','Pool','{\"heading\":\"12×6 m pool — fenced and secure\",\"text\":\"The pool measures 12 by 6 metres, fully fenced for children\'s safety. Sun loungers, parasols, outdoor shower and garden furniture around the pool. Open from May to October.\",\"image\":[\"villa-plaisance-jardin-exterieur-04.webp\",\"villa-plaisance-piscine-privee-01.webp\",\"villa-plaisance-piscine-privee-05.webp\"],\"image_alt\":\"Piscine clôturée 12×6 m — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',3,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (82,'espaces-exterieurs','es','prose','Piscina','{\"heading\":\"Piscina de 12×6 m — vallada y segura\",\"text\":\"La piscina mide 12 por 6 metros, completamente vallada para la seguridad de los niños. Tumbonas, sombrillas, ducha exterior y mobiliario de jardín. Abierta de mayo a octubre.\",\"image\":[\"villa-plaisance-jardin-exterieur-04.webp\",\"villa-plaisance-piscine-privee-01.webp\",\"villa-plaisance-piscine-privee-05.webp\"],\"image_alt\":\"Piscine clôturée 12×6 m — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',3,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (83,'espaces-exterieurs','en','prose','Terraces','{\"heading\":\"Shaded terraces facing the vineyards\",\"text\":\"A 40 m² covered terrace facing south, perfect for outdoor dining, sunset aperitifs and quiet mornings with coffee. Direct view of the vineyards of Châteauneuf-du-Pape.\",\"image\":[\"villa-plaisance-chambre-annees-70-11.webp\",\"villa-plaisance-facade-11.webp\",\"villa-plaisance-jardin-exterieur-05.webp\"],\"image_alt\":\"Terrasse ombragée orientée sud — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',4,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (84,'espaces-exterieurs','es','prose','Terrazas','{\"heading\":\"Terrazas sombreadas frente a los viñedos\",\"text\":\"Terraza cubierta de 40 m² orientada al sur, perfecta para comer al aire libre, aperitivos al atardecer y mañanas tranquilas con café. Vista directa a los viñedos de Châteauneuf-du-Pape.\",\"image\":[\"villa-plaisance-chambre-annees-70-11.webp\",\"villa-plaisance-facade-11.webp\",\"villa-plaisance-jardin-exterieur-05.webp\"],\"image_alt\":\"Terrasse ombragée orientée sud — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',4,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (85,'espaces-exterieurs','en','prose','Garden','{\"heading\":\"Provençal garden — olive trees, lavender and herbs\",\"text\":\"A landscaped garden with century-old olive trees, lavender, old roses and aromatic herbs. BBQ area with charcoal grill, pétanque court, swing for children.\",\"image\":[\"villa-plaisance-piscine-privee-06.webp\",\"villa-plaisance-jardin-exterieur-20.webp\",\"villa-plaisance-jardin-exterieur-09.webp\"],\"image_alt\":\"Jardin provençal avec oliviers centenaires — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',5,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (86,'espaces-exterieurs','es','prose','Jardín','{\"heading\":\"Jardín provenzal — olivos, lavanda y hierbas aromáticas\",\"text\":\"Un jardín arbolado con olivos centenarios, lavanda, rosales antiguos y hierbas aromáticas. Zona de barbacoa con parrilla de carbón, campo de petanca, columpio para niños.\",\"image\":[\"villa-plaisance-piscine-privee-06.webp\",\"villa-plaisance-jardin-exterieur-20.webp\",\"villa-plaisance-jardin-exterieur-09.webp\"],\"image_alt\":\"Jardin provençal avec oliviers centenaires — Villa Plaisance, Bédarrides\",\"lead\":\"0\"}',5,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
