INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (91,'espaces-exterieurs','en','cta','CTA Outdoors','{\"heading\":\"Enjoy the outdoors in Provence\",\"text\":\"B&B (Sept–June) or private villa (Jul–Aug) — the outdoor spaces are always included. Direct booking = best rate guaranteed.\",\"buttons\":[{\"text\":\"Check availability\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"dark\":true,\"button_url\":\"\\/contact\"}',8,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
