INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (95,'location-villa-provence','en','hero','Hero Villa','{\"title\":\"The Entire Villa — All yours\",\"subtitle\":\"4 bedrooms · Private pool 12×6 m · Up to 10 guests · July & August\",\"buttons\":[{\"text\":\"Book the villa\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"image\":[\"villa-plaisance-piscine-privee-03.webp\",\"villa-plaisance-jardin-exterieur-21.webp\",\"villa-plaisance-facade-04.webp\",\"villa-plaisance-detail-decoration-03.webp\"],\"image_alt\":\"Villa Plaisance en exclusivité avec piscine privée et jardin provençal\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (96,'location-villa-provence','es','hero','Hero Villa','{\"title\":\"La Villa entera — Solo para usted\",\"subtitle\":\"4 habitaciones · Piscina privada 12×6 m · Hasta 10 personas · Julio y agosto\",\"buttons\":[{\"text\":\"Reservar la villa\",\"url\":\"\\/contact\",\"style\":\"primary\"}],\"image\":[\"villa-plaisance-piscine-privee-03.webp\",\"villa-plaisance-jardin-exterieur-21.webp\",\"villa-plaisance-facade-04.webp\",\"villa-plaisance-detail-decoration-03.webp\"],\"image_alt\":\"Villa Plaisance en exclusivité avec piscine privée et jardin provençal\",\"compact\":\"0\"}',1,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (97,'location-villa-provence','en','prose','Intro Villa','{\"heading\":\"The entire villa in full autonomy\",\"text\":\"In July and August, Villa Plaisance opens its doors as a full rental. Four bedrooms, ten guests, a private pool, a Provençal garden, a fully equipped kitchen. You are at home. We remain available if needed, but you set your own pace.\",\"lead\":true}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (98,'location-villa-provence','es','prose','Intro Villa','{\"heading\":\"La villa entera con total autonomía\",\"text\":\"En julio y agosto, Villa Plaisance abre sus puertas en alquiler completo. Cuatro habitaciones, diez personas, piscina privada, jardín provenzal, cocina totalmente equipada. Está en su casa. Seguimos disponibles si lo necesita, pero usted marca su propio ritmo.\",\"lead\":true}',2,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
