INSERT INTO `vp_sections` (`id`, `page_slug`, `lang`, `block_type`, `title`, `content`, `position`, `active`, `created_at`, `updated_at`) VALUES (102,'location-villa-provence','es','piscine','Piscina','{\"heading\":\"Piscina privada vallada de 12×6 m\",\"text\":\"Reservada exclusivamente para su grupo, 24\\/7. Tumbonas, sombrillas, mesa de jardín, salón exterior y ducha solar. Vallada para la seguridad de los niños.\",\"image\":[\"villa-plaisance-piscine-privee-03.webp\",\"villa-plaisance-piscine-privee-07.webp\",\"villa-plaisance-piscine-privee-08.webp\"],\"image_alt\":\"Piscine privée clôturée 12×6 m — Villa Plaisance, Bédarrides\"}',4,1,'2026-03-30 09:50:37','2026-03-30 11:00:09');
